INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1265, 190567, 10, 1003, '[转贴]假如我是洛丽塔', '洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”
<br>
<br>　　何等惊心动魄的表白，在现实惨淡的阳光下栩栩生辉，如同山脉入口处迸涌的毁灭性的岩浆，既纯洁又邪恶，在无边的黑暗中颤抖的死亡之火紧紧地牵引住我的目光与灵魂，时而那些无情地撕扯着我的理想、向着陌生的路径狂奔的文字又令我感到痛苦万分。
<br>
<br>　　“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”
<br>
<br>　　哦，洛丽塔，在比托马斯&#183;沃尔夫更疯狂的文字中被爱着的无知的灵魂，披着自然的光泽，在痉挛的心灵中浮动的阴险的诱惑者，倘若我是你，我会化作那被点燃之火，而不是随风飘散的笑声和讨价还价的鬼人精。成全他成为另一个但丁或比特拉克，“在花粉和尘埃中奔跑着”，象一朵飘浮在空中的花。
<br>
<br>　　“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”
<br>
<br>　　在浓烈的沸腾的血液中起伏的鲜艳影子，在天低云暗的公路上恣意玩耍的小巫，在汽车的尖叫中遗失在上帝眼里的细菌。哦，洛丽塔，我不会是你，因为我不会把他疯狂而温柔的热情玩弄于股掌之间，对他的哀伤熟视无睹，欺瞒他的整个世界，把他推向地狱而又不伸出一个希望的指头。他比第一钢琴协奏曲更充满了春天的气息，有着更浩荡的生命的洪流。尽管他有着可怕的、变态的意志，自我毁灭而又把我投进毁灭之海。
<br>
<br>　　“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”
<br>
<br>　　光与火，浸透他心灵的每一道运动轨迹，每一次残忍却天真的背叛，使他永不得安宁、痛苦的思维永不停息的银铃般的娇笑。可怜的洛丽塔！可恨的洛丽塔！让人爱不释手的洛丽塔。因为我不是你，所以我很快是空白的记忆，不是那充满蓝天的不可捉摸的影子。哦，如果我是你，我又会如何用脚尖划出最美好的弧形以纠缠他那简单灵魂的足迹，在他的手心里留下沙滩的晨梦和夜海洋的呓语，在他的叹息里点上星光一样恍忽而柔软的标记，改变他的、和我的命运的方向。
<br>
<br>　　多么灿烂的日子。假如我是洛丽塔！
<br>
<br>　　附录：作品赏析
<br>
<br>　　小说以狱中忏悔的形式叙述了主人公汉&#183;汉勃特的一生。从表面看来，这是一个具有性反常心理的中年男子与一个典型的追求物欲享受的美国少女间的颇有些色情意味的故事，有着自己的意义层面，而且为数不少的评论也正是从这一角度展开的。最初纳博科夫写完作品在国内寻求出版时到处碰壁，而且在宽容的法国出版后屡被批评是一部非道德甚至反美的小说，也是由于这部小说一眼看去必定会产生的这种理解（即使在九十年代，情况也是如此。一个有趣的例子是，在因特网上键入主题词“洛丽塔”，所调出的全部网页中至少有百分之五十涉及到性和色情）。然而对这部作品的理解决不能仅限于作品表层结构给人的直接感受。要全面读解这部小说，我们还应了解这样一些背景情况：在一篇论述《洛丽塔》的文章中，纳博科夫曾告诉我们他最初的灵感来良于一幅前所未有的由人猿在强迫调驯下作的画：“这幅素描显示了囚禁那可怜生物的笼子的铁栅栏。”显然铁栅栏被人猿当成了现实的必然限定。这幅画对一个感觉到生活中充满了各种各样――政治的和心理的、社会的和个人的――囚笼的作者来说极富启悟，同时也给我们理解《洛丽塔》提供了一个切人点――汉勃特的人生囚笼；此外在《洛丽塔》之前，纳博科夫曾写过一个短篇《失望》，其疯狂而自觉的主人公――能看得出是汉&#183;汉勃特的前身――设计了一项复杂的罪行，但这“完美的罪行”及记载犯罪实施的日记却显示了主人公无法理解：偶然的现实是不能操纵的，以及“艺术的创造远比生活现实来得真实。”这一认识在《洛丽塔》中得到了更为全面的展现。我们在作品中可看到，汉勃特在他的初恋情人安娜贝尔为他在欲望和占有之间设立了沟壑以后，竭力想跨越这沟壑：他始终在寻觅“宁芙”，甚至不择手段――委屈地娶了洛丽塔之母夏洛特并幻想着谋杀。可在到达了欲望那欣悦的彼岸后，汉勃特却处在了一个不停地逃跑――躲避的痛苦过程中，最终只是在监狱中他才从反思中懂得了是欲望而不是占有（也即是艺术创造而不是现实）才是一种追求的境界，才是真正的超越现实，所以在监狱里“只有词语可以玩弄”的汉勃特用语言倒是成功地把他和洛丽塔摆渡到了那种“想象的极乐”境地。由此，汉勃特的性的欲望就成了对艺术创造欲望的一个隐喻。所以，纳博科夫在《洛丽塔》中主要想表现的就是他对艺术创造与现实之间关系的这样一种看法。至于他采用这样的“色情”题材，则与他的艺术见解有关，他认为：“我所有小说的一个功能就是要证明一般的小说并不存在，我所写的书属于一种主观的和特定的事件。”正如《阿达》选择兄妹乱伦的题材，《灰火》类同于注释读本一样，《洛丽塔》也是这样一部有意为之的作品。 
<br>
<br>　　小说还显示了一种卓绝的对语言的自觉。纳博科夫，正如“只有词语可以玩弄”的关在监狱里的主人公，也是词汇游戏场上的一个高手，在词汇的游戏场上，人们能享有一种灵活性，一种在现实世界中毫无希望获得的颐指气使的权利。作者充分利用了这一特权，在创作中令人眼花缭乱地将梦幻和事实、韵文和散文、情趣和智慧、虚构与现实交织在一起，显示了他高超的驾驭语言的能力。纳博科夫自认《洛丽塔》是他与英语间的风流韵事，恰好也是对作品在这方面努力的一个现实的注脚。所以阅读这部小说时，从文字的迷宫中寻找意义出路的努力也同样给人以极大的乐趣。（孔小炯）', '洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”

何等惊心动魄的表白，在现实惨淡的阳光下栩栩生辉，如同山脉入口处迸涌的毁灭性的岩浆，既纯洁又邪恶，在无边的黑暗中颤抖的死亡之火紧紧地牵引住我的目光与灵魂，时而那些无情地撕扯着我的理想、向着陌生的路径狂奔的文字又令我感到痛苦万分。

“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”

哦，洛丽塔，在比托马斯·沃尔夫更疯狂的文字中被爱着的无知的灵魂，披着自然的光泽，在痉挛的心灵中浮动的阴险的诱惑者，倘若我是你，我会化作那被点燃之火，而不是随风飘散的笑声和讨价还价的鬼人精。成全他成为另一个但丁或比特拉克，“在花粉和尘埃中奔跑着”，象一朵飘浮在空中的花。

“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”

在浓烈的沸腾的血液中起伏的鲜艳影子，在天低云暗的公路上恣意玩耍的小巫，在汽车的尖叫中遗失在上帝眼里的细菌。哦，洛丽塔，我不会是你，因为我不会把他疯狂而温柔的热情玩弄于股掌之间，对他的哀伤熟视无睹，欺瞒他的整个世界，把他推向地狱而又不伸出一个希望的指头。他比第一钢琴协奏曲更充满了春天的气息，有着更浩荡的生命的洪流。尽管他有着可怕的、变态的意志，自我毁灭而又把我投进毁灭之海。

“洛丽塔，我生命之光，我欲念之火。我的罪恶，我的灵魂。”

光与火，浸透他心灵的每一道运动轨迹，每一次残忍却天真的背叛，使他永不得安宁、痛苦的思维永不停息的银铃般的娇笑。可怜的洛丽塔！可恨的洛丽塔！让人爱不释手的洛丽塔。因为我不是你，所以我很快是空白的记忆，不是那充满蓝天的不可捉摸的影子。哦，如果我是你，我又会如何用脚尖划出最美好的弧形以纠缠他那简单灵魂的足迹，在他的手心里留下沙滩的晨梦和夜海洋的呓语，在他的叹息里点上星光一样恍忽而柔软的标记，改变他的、和我的命运的方向。

多么灿烂的日子。假如我是洛丽塔！

